    //MARK: - CONSTRUCTORS
    /// initialize from the fundamental type value
    public init(fundamental: FundamentalType) { self = fundamental }

    /// initialize from the underlying type value
    public init?<T: SDAI.UnderlyingType>(possiblyFrom underlyingType: T?){
      guard let underlyingType = underlyingType else { return nil }

      if let base = underlyingType as? sCLASSIFIED_ITEM {
        self = ._CLASSIFIED_ITEM(base)
      }
      else if let base = sCLASSIFIED_ITEM(possiblyFrom: underlyingType) {
        self = ._CLASSIFIED_ITEM(base)
      }
      else { return nil }
    }

    /// initialize from complex entity
    public init?(possiblyFrom complex: SDAI.ComplexEntity?) {
      guard let complex = complex else { return nil }

      if let base = complex.entityReference(eACTION.self) {self = ._ACTION(base.pRef) }
      else if let base = complex.entityReference(eACTION_DIRECTIVE.self) {self = ._ACTION_DIRECTIVE(base.pRef) }
      else if let base = complex.entityReference(eACTION_DIRECTIVE_RELATIONSHIP.self) {self = ._ACTION_DIRECTIVE_RELATIONSHIP(base.pRef) }
      else if let base = complex.entityReference(eACTION_METHOD.self) {self = ._ACTION_METHOD(base.pRef) }
      else if let base = complex.entityReference(eACTION_METHOD_RELATIONSHIP.self) {self = ._ACTION_METHOD_RELATIONSHIP(base.pRef) }
      else if let base = complex.entityReference(eACTION_PROPERTY.self) {self = ._ACTION_PROPERTY(base.pRef) }
      else if let base = complex.entityReference(eACTION_PROPERTY_REPRESENTATION.self) {self = ._ACTION_PROPERTY_REPRESENTATION(base.pRef) }
      else if let base = complex.entityReference(eACTION_RELATIONSHIP.self) {self = ._ACTION_RELATIONSHIP(base.pRef) }
      else if let base = complex.entityReference(eACTION_REQUEST_SOLUTION.self) {self = ._ACTION_REQUEST_SOLUTION(base.pRef) }
      else if let base = complex.entityReference(eACTION_REQUEST_STATUS.self) {self = ._ACTION_REQUEST_STATUS(base.pRef) }
      else if let base = complex.entityReference(eACTION_RESOURCE.self) {self = ._ACTION_RESOURCE(base.pRef) }
      else if let base = complex.entityReference(eACTION_RESOURCE_RELATIONSHIP.self) {self = ._ACTION_RESOURCE_RELATIONSHIP(base.pRef) }
      else if let base = complex.entityReference(eACTION_RESOURCE_REQUIREMENT.self) {self = ._ACTION_RESOURCE_REQUIREMENT(base.pRef) }
